import { __ } from "@wordpress/i18n";
import { useBlockProps } from "@wordpress/block-editor";
import "./editor.scss";
import { InnerBlocks } from "@wordpress/block-editor";

const { InspectorControls } = wp.blockEditor;
const {
	PanelBody,
	Button,
	ResponsiveWrapper,
	SelectControl,
	ToggleControl,
	TextControl,
} = wp.components;
const { Fragment } = wp.element;
const { MediaUpload, MediaUploadCheck } = wp.blockEditor;

export function Edit(props) {
	const { attributes, setAttributes } = props;
	const onSelectMedia = (media) => {
		setAttributes({
			mediaId: media.id,
			mediaUrl: media.url,
		});
	};

	const media = wp.data.select("core").getMedia(attributes.mediaId);

	const removeMedia = () => {
		setAttributes({
			mediaId: 0,
			mediaUrl: "",
		});
	};
	return (
		<>
			<InspectorControls>
				<PanelBody title={__("Select block image", "acm")} initialOpen={true}>
					<div className="editor-post-featured-image">
						<MediaUploadCheck>
							<MediaUpload
								onSelect={onSelectMedia}
								value={attributes.mediaId}
								allowedTypes={["image"]}
								render={({ open }) => (
									<Button
										className={
											attributes.mediaId == 0
												? "editor-post-featured-image__toggle"
												: "editor-post-featured-image__preview"
										}
										onClick={open}
									>
										{attributes.mediaId == 0 && __("Choose an image", "acm")}
										{media != undefined && (
											<ResponsiveWrapper
												naturalWidth={media.media_details.width}
												naturalHeight={media.media_details.height}
											>
												<img src={media.source_url} />
											</ResponsiveWrapper>
										)}
									</Button>
								)}
							/>
						</MediaUploadCheck>
						{attributes.mediaId != 0 && (
							<MediaUploadCheck>
								<Button onClick={removeMedia} isLink isDestructive>
									{__("Remove image", "acm")}
								</Button>
							</MediaUploadCheck>
						)}
						{attributes.mediaId != 0 && (
							<MediaUploadCheck>
								<MediaUpload
									title={__("Replace image", "awp")}
									value={attributes.mediaId}
									onSelect={onSelectMedia}
									allowedTypes={["image"]}
									render={({ open }) => (
										<Button onClick={open} variant="secondary" isLarge>
											{__("Replace image", "awp")}
										</Button>
									)}
								/>
							</MediaUploadCheck>
						)}
						<Button isLink>
							<a
								className="custom-link-sidebar"
								target="_blank"
								href="http://identitystandards.acm.org/tools1.html"
							>
								{__("Download ACM banners and logos here!", "acm")}
							</a>
						</Button>
					</div>
				</PanelBody>
				<PanelBody title={__("Banner text line 1", "acm")} initialOpen={true}>
					<TextControl
						label={__("Line 1", "acm")}
						value={attributes.textLine1}
						onChange={(value) => setAttributes({ textLine1: value })}
					/>
				</PanelBody>
				<PanelBody title={__("Banner text line 2", "acm")} initialOpen={true}>
					<TextControl
						label={__("Line 2", "acm")}
						value={attributes.textLine2}
						onChange={(value) => setAttributes({ textLine2: value })}
					/>
				</PanelBody>
				<PanelBody title={__("Banner text line 3", "acm")} initialOpen={true}>
					<TextControl
						label={__("Line 3", "acm")}
						value={attributes.textLine3}
						onChange={(value) => setAttributes({ textLine3: value })}
					/>
				</PanelBody>
			</InspectorControls>
			<div {...useBlockProps()}>
				<img src={attributes.mediaUrl} alt={attributes.mediaId} />
				<div className="dots"></div>
				<div className="container">
					<p className="small">{attributes.textLine1}</p>
					<p className="big">{attributes.textLine2}</p>
					<p>{attributes.textLine3}</p>
				</div>
			</div>
		</>
	);
}

export function Save() {
	return <></>;
}
